import ast, sys

with open('myproject/myproject.py') as f:
    source = f.read()

tree = ast.parse(source)

checks = {
    'State subclass': False,
    'submissions: list[dict]': False,
    'last_submission: dict': False,
    'submission_count cached var': False,
    'handle_submit event': False,
    'rx.form or rx.form.root call': False,
}

for node in ast.walk(tree):
    # Check for State class
    if isinstance(node, ast.ClassDef) and node.name == 'State':
        checks['State subclass'] = True
        # Look at class body for annotations
        for item in node.body:
            if isinstance(item, ast.AnnAssign):
                name = item.target.id if isinstance(item.target, ast.Name) else ''
                ann = ast.unparse(item.annotation)
                if name == 'submissions' and 'list' in ann and 'dict' in ann:
                    checks['submissions: list[dict]'] = True
                if name == 'last_submission' and 'dict' in ann:
                    checks['last_submission: dict'] = True
            # Check for cached computed var
            if isinstance(item, ast.FunctionDef):
                decorators = [ast.unparse(d) for d in item.decorator_list]
                if item.name == 'submission_count' and any('rx.var' in d for d in decorators):
                    checks['submission_count cached var'] = True
                if item.name == 'handle_submit' and any('rx.event' in d for d in decorators):
                    checks['handle_submit event'] = True

# Check for rx.form.root call
for node in ast.walk(tree):
    if isinstance(node, ast.Call):
        func = ast.unparse(node.func)
        if 'rx.form' in func:
            checks['rx.form or rx.form.root call'] = True

print('Verification results:')
all_ok = True
for check, passed in checks.items():
    status = '✓' if passed else '✗'
    print(f'  {status} {check}')
    if not passed:
        all_ok = False

sys.exit(0 if all_ok else 1)
"
